mapper.select:
SELECT B.BOARD_NO, B.BOARD_TITLE, B.BOARD_WRITER, M.MEM_NAME AS "boardWriterName", B.CREATE_DATE, B.VIEW_COUNT AS "viewCount", BT.BTYPE_NAME AS "categoryName", (SELECT COUNT(*) FROM BOARD_LIKE L WHERE L.BOARD_NO = B.BOARD_NO) AS "likeCount" FROM BOARD B JOIN MEMBER M ON (B.BOARD_WRITER = M.MEM_NO) JOIN DEPARTMENT D ON (M.DEPT_NO = D.DEPT_NO) LEFT JOIN UNI_BOARD_TYPE UBT ON (B.UBTYPE_NO = UBT.UBTYPE_NO) LEFT JOIN BOARD_TYPE BT ON (UBT.BTYPE_NO = BT.BTYPE_NO) WHERE B.STATUS = 'Y' AND D.UNI_NO = #{uniNo}
AND BT.BTYPE_NAME = #{category}
ORDER BY B.BOARD_NO DESC

mapper.update:
UPDATE BOARD
	SET STATUS = 'N'
WHERE BOARD_NO = #{boardNo}
